// Golden-query suite for docs search relevance. Runs against the REAL
// generated index (lib/generated/docs-search-index.ts — rebuilt on every
// site build), exercising the shipped searchDocs() path (NLWeb /ask + MCP)
// which shares ranking rules with app/api/search via lib/search-relevance:
//   • doc-type weighting (guide/concept/cookbook above reference)
//   • exact-title floor (title match always surfaces top-3)
//   • synonym expansion + typo tolerance (queries ≥ 4 chars)
//   • zero-result rescue suggestions

import { describe, expect, it } from "vitest";
import { searchDocs } from "@/lib/doc-search";
import { DOCS_SEARCH_INDEX } from "@/lib/generated/docs-search-index";
import { typoToleranceFor } from "@/lib/search-relevance";
import { zeroResultSuggestions } from "@/lib/search-suggest";
import { expandQuery } from "@/lib/search-synonyms";

/** Top-3 result paths for a query (id = raw /docs/... path). */
function top3(query: string): string[] {
  // Arrange + Act
  return searchDocs(query, 3).map((h) => h.id);
}

// ── Golden queries: every listed URL must appear in the top 3 ───────────────
const MUST_INCLUDE: Array<[query: string, urls: string[]]> = [
  // Exact-title floor: reference pages still surface despite low type weight.
  ["commit", ["/docs/skills/spotlights/commit", "/docs/reference/skills/commit"]],
  ["memory", ["/docs/reference/skills/memory", "/docs/skills/spotlights/memory"]],
  // Prefix-title floor on a camel-cased hook name.
  ["worktree", ["/docs/reference/hooks/worktree-create"]],
  // Concept pages beat the reference index page for a broad term.
  ["hooks", ["/docs/hooks/overview"]],
  // Natural-language query (stopwords stripped, write→create synonym).
  ["how do I write a skill", ["/docs/skills/writing-skills"]],
  // Multi-term guide query.
  ["adopt claude code release", ["/docs/guides/cc-adoption"]],
  // Lab pages (regenerated index).
  ["triage", ["/docs/showcase/lab/triage-board"]],
  ["lab", ["/docs/showcase/lab"]],
  // Exact/prefix titles across doc types.
  ["installation", ["/docs/getting-started/installation"]],
  ["hook debugging", ["/docs/troubleshooting/hook-debugging"]],
  ["release channels", ["/docs/getting-started/release-channels"]],
  ["graph memory", ["/docs/memory/graph-memory"]],
  ["changelog", ["/docs/changelog"]],
];

// ── Looser golden queries: at least one listed URL in the top 3 ─────────────
const ANY_OF: Array<[query: string, urls: string[]]> = [
  // Typo cases (edit distance 1, incl. transposition) — need query ≥ 4 chars.
  [
    "commt",
    ["/docs/skills/spotlights/commit", "/docs/reference/skills/commit"],
  ],
  [
    "memroy",
    [
      "/docs/memory/overview",
      "/docs/memory/graph-memory",
      "/docs/reference/skills/memory",
      "/docs/skills/spotlights/memory",
      "/docs/cookbook/setup-memory",
    ],
  ],
  ["installtion", ["/docs/getting-started/installation"]],
  // Synonym cases.
  [
    "subagent", // → agent
    [
      "/docs/agents/overview",
      "/docs/agents/choosing-an-agent",
      "/docs/agents/multi-agent-patterns",
    ],
  ],
  ["playground", ["/docs/showcase/lab"]], // → lab
  [
    "cmd", // → command / slash-command
    [
      "/docs/skills/command-skills",
      "/docs/hooks/spotlights/dangerous-command-blocker",
    ],
  ],
];

describe("golden queries — top-3 relevance", () => {
  it.each(MUST_INCLUDE)("%s", (query, urls) => {
    // Act
    const results = top3(query);
    // Assert
    for (const url of urls) {
      expect(results, `query "${query}" top-3 = ${results.join(", ")}`).toContain(url);
    }
  });

  it.each(ANY_OF)("%s (any-of)", (query, urls) => {
    // Act
    const results = top3(query);
    // Assert
    expect(
      urls.some((u) => results.includes(u)),
      `query "${query}" top-3 = ${results.join(", ")} — expected one of ${urls.join(", ")}`,
    ).toBe(true);
  });
});

describe("zero-result rescue", () => {
  it.each([["xyzzyq blorp"], ["qwzk vprt"]])(
    "suggests closest titles for %s",
    (query) => {
      // Arrange — a query no page matches
      expect(searchDocs(query, 3)).toHaveLength(0);
      // Act
      const suggestions = zeroResultSuggestions(query, DOCS_SEARCH_INDEX, 3);
      // Assert — never a dead end
      expect(suggestions.length).toBeGreaterThan(0);
      for (const s of suggestions) {
        expect(s.url).toMatch(/^\//);
        expect(s.title.length).toBeGreaterThan(0);
      }
    },
  );

  it("suggests the real title for a near-miss query", () => {
    const suggestions = zeroResultSuggestions("memroy graph", DOCS_SEARCH_INDEX, 3);
    expect(suggestions.map((s) => s.url)).toContain("/docs/memory/graph-memory");
  });
});

describe("ranking primitives", () => {
  it("gates typo tolerance to queries of 4+ chars", () => {
    expect(typoToleranceFor("abc")).toBe(0);
    expect(typoToleranceFor("abcd")).toBe(1);
  });

  it("expands synonyms without duplicating originals", () => {
    const { original, synonyms } = expandQuery("agent hooks");
    expect(original).toEqual(["agent", "hooks"]);
    expect(synonyms).toContain("subagent");
    expect(synonyms).not.toContain("agent");
  });
});
